const crypto = require('crypto');

function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return `${salt}:${hash}`;
}

function verifyPassword(password, storedHash) {
  const [salt, hash] = storedHash.split(':');
  const verifyHash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return hash === verifyHash;
}

// Example usage
function registerUser(username, password) {
  const hashedPassword = hashPassword(password);
  // Store username and hashedPassword in your database
  return {
    username,
    hashedPassword
  };
}

function loginUser(password, storedHashedPassword) {
  return verifyPassword(password, storedHashedPassword);
}

// Demo
const user = registerUser('john_doe', 'mySecretPassword123');
console.log('Registered user:', user.username);
console.log('Stored hash:', user.hashedPassword);

const isValid = loginUser('mySecretPassword123', user.hashedPassword);
console.log('Login with correct password:', isValid);

const isInvalid = loginUser('wrongPassword', user.hashedPassword);
console.log('Login with wrong password:', isInvalid);

module.exports = { hashPassword, verifyPassword, registerUser, loginUser };